"use client"
import {
  FieldError,
  FieldValues,
  FormProvider,
  useForm,
  useFormContext,
} from "react-hook-form"
import { Button } from "@/components/atoms"
import { zodResolver } from "@hookform/resolvers/zod"
import LocalizedClientLink from "@/components/molecules/LocalizedLink/LocalizedLink"
import { LabeledInput } from "@/components/cells"
import { loginFormSchema, LoginFormData } from "./schema"
import { useState } from "react"
import { login } from "@/lib/data/customer"
import { useRouter } from "next/navigation"
import { SocialLoginButtons } from "@/components/molecules/SocialLoginButtons"

export const LoginForm = () => {
  const methods = useForm<LoginFormData>({
    resolver: zodResolver(loginFormSchema),
    defaultValues: {
      email: "",
      password: "",
    },
  })

  return (
    <FormProvider {...methods}>
      <Form />
    </FormProvider>
  )
}

const Form = () => {
  const [error, setError] = useState("")
  const [socialError, setSocialError] = useState("")
  const {
    handleSubmit,
    register,
    formState: { errors, isSubmitting },
  } = useFormContext()
  const router = useRouter()

  const submit = async (data: FieldValues) => {
    const formData = new FormData()
    formData.append("email", data.email)
    formData.append("password", data.password)

    const res = await login(formData)
    if (res) {
      setError(res)
      return
    }
    setError("")
    router.push("/user")
  }

  return (
    <main className="flex min-h-[calc(100vh-64px)] items-center justify-center px-4 py-12">
      <div className="w-full max-w-md space-y-6">
        {/* Heading */}
        <div className="text-center space-y-1">
          <h1
            className="font-barlow-condensed font-bold"
            style={{ fontSize: 32, color: "var(--text-primary, #F0EEFF)" }}
          >
            Welcome back
          </h1>
          <p style={{ fontSize: 15, color: "var(--text-secondary, #B8B0D8)" }}>
            Sign in to your account
          </p>
        </div>

        {/* Social Login Options */}
        <SocialLoginButtons
          variant="login"
          onError={setSocialError}
          disabled={isSubmitting}
        />

        {socialError && (
          <p className="label-md text-negative text-center">{socialError}</p>
        )}

        {/* Divider */}
        <div className="relative">
          <div className="absolute inset-0 flex items-center">
            <span
              className="w-full border-t"
              style={{ borderColor: "var(--border-default, #2C2A4A)" }}
            />
          </div>
          <div className="relative flex justify-center text-sm">
            <span
              className="px-3"
              style={{
                background: "var(--bg-surface-1, #18162A)",
                color: "var(--text-tertiary, #7B72A8)",
              }}
            >
              or
            </span>
          </div>
        </div>

        {/* Email/Password Login Form */}
        <form onSubmit={handleSubmit(submit)} className="space-y-4">
          <LabeledInput
            label="E-mail"
            placeholder="Your e-mail address"
            error={errors.email as FieldError}
            {...register("email")}
          />
          <LabeledInput
            label="Password"
            placeholder="Your password"
            type="password"
            error={errors.password as FieldError}
            {...register("password")}
          />
          <div className="flex justify-end">
            <LocalizedClientLink
              href="/user/forgot-password"
              className="text-sm font-medium"
              style={{ color: "var(--brand-primary, #8B5CF6)" }}
            >
              Forgot password?
            </LocalizedClientLink>
          </div>
          {error && <p className="label-md text-negative">{error}</p>}
          <Button
            className="w-full rounded-[14px]"
            disabled={isSubmitting}
            style={{
              background: "var(--brand-primary, #8B5CF6)",
              color: "#fff",
              boxShadow: "0 2px 8px rgba(139, 92, 246, 0.25)",
            }}
          >
            Sign in
          </Button>
        </form>

        <p
          className="text-center text-sm"
          style={{ color: "var(--text-secondary, #B8B0D8)" }}
        >
          Don&apos;t have an account?{" "}
          <LocalizedClientLink
            href="/user/register"
            className="font-medium"
            style={{ color: "var(--brand-primary, #8B5CF6)" }}
          >
            Sign up
          </LocalizedClientLink>
        </p>
      </div>
    </main>
  )
}

"use client"
import {
  FieldError,
  FieldValues,
  FormProvider,
  useForm,
  useFormContext,
} from "react-hook-form"
import { Button } from "@/components/atoms"
import { zodResolver } from "@hookform/resolvers/zod"
import { LabeledInput } from "@/components/cells"
import { registerFormSchema, RegisterFormData } from "./schema"
import { signup } from "@/lib/data/customer"
import { useState } from "react"
import Link from "next/link"
import { PasswordValidator } from "@/components/cells/PasswordValidator/PasswordValidator"
import { SocialLoginButtons } from "@/components/molecules/SocialLoginButtons"

export const RegisterForm = () => {
  const methods = useForm<RegisterFormData>({
    resolver: zodResolver(registerFormSchema),
    defaultValues: {
      firstName: "",
      lastName: "",
      phone: "",
      email: "",
      password: "",
    },
  })

  return (
    <FormProvider {...methods}>
      <Form />
    </FormProvider>
  )
}

const Form = () => {
  const [passwordError, setPasswordError] = useState({
    isValid: false,
    lower: false,
    upper: false,
    "8chars": false,
    symbolOrDigit: false,
  })
  const [error, setError] = useState()
  const [socialError, setSocialError] = useState("")
  const {
    handleSubmit,
    register,
    watch,
    formState: { errors, isSubmitting },
  } = useFormContext()

  const submit = async (data: FieldValues) => {
    const formData = new FormData()
    formData.append("email", data.email)
    formData.append("password", data.password)
    formData.append("first_name", data.firstName)
    formData.append("last_name", data.lastName)
    formData.append("phone", data.phone)

    const res = passwordError.isValid && (await signup(formData))

    if (res && !res?.id) setError(res)
  }

  return (
    <main className="flex min-h-[calc(100vh-64px)] items-center justify-center px-4 py-12">
      <div className="w-full max-w-md space-y-6">
        {/* Heading */}
        <div className="text-center space-y-1">
          <h1
            className="font-barlow-condensed font-bold"
            style={{ fontSize: 32, color: "var(--text-primary, #F0EEFF)" }}
          >
            Create your account
          </h1>
          <p style={{ fontSize: 15, color: "var(--text-secondary, #B8B0D8)" }}>
            Join the marketplace for competitive players
          </p>
        </div>

        {/* Social Registration Options */}
        <SocialLoginButtons
          variant="register"
          onError={setSocialError}
          disabled={isSubmitting}
        />

        {socialError && (
          <p className="label-md text-negative text-center">{socialError}</p>
        )}

        {/* Divider */}
        <div className="relative">
          <div className="absolute inset-0 flex items-center">
            <span
              className="w-full border-t"
              style={{ borderColor: "var(--border-default, #2C2A4A)" }}
            />
          </div>
          <div className="relative flex justify-center text-sm">
            <span
              className="px-3"
              style={{
                background: "var(--bg-surface-1, #18162A)",
                color: "var(--text-tertiary, #7B72A8)",
              }}
            >
              or
            </span>
          </div>
        </div>

        {/* Email/Password Registration Form */}
        <form onSubmit={handleSubmit(submit)} className="space-y-4">
          <div className="flex flex-col md:flex-row gap-4">
            <LabeledInput
              className="md:w-1/2"
              label="First name"
              placeholder="Your first name"
              error={errors.firstName as FieldError}
              {...register("firstName")}
            />
            <LabeledInput
              className="md:w-1/2"
              label="Last name"
              placeholder="Your last name"
              error={errors.lastName as FieldError}
              {...register("lastName")}
            />
          </div>
          <div className="flex flex-col md:flex-row gap-4">
            <LabeledInput
              className="md:w-1/2"
              label="E-mail"
              placeholder="Your e-mail address"
              error={errors.email as FieldError}
              {...register("email")}
            />
            <LabeledInput
              className="md:w-1/2"
              label="Phone"
              placeholder="Your phone number"
              error={errors.phone as FieldError}
              {...register("phone")}
            />
          </div>
          <div>
            <LabeledInput
              className="mb-2"
              label="Password"
              placeholder="Your password"
              type="password"
              error={errors.password as FieldError}
              {...register("password")}
            />
            <PasswordValidator
              password={watch("password")}
              setError={setPasswordError}
            />
          </div>

          {error && <p className="label-md text-negative">{error}</p>}
          <Button
            className="w-full rounded-[14px]"
            disabled={isSubmitting}
            loading={isSubmitting}
            style={{
              background: "var(--brand-primary, #8B5CF6)",
              color: "#fff",
              boxShadow: "0 2px 8px rgba(139, 92, 246, 0.25)",
            }}
          >
            Create account
          </Button>
        </form>

        <p
          className="text-center text-sm"
          style={{ color: "var(--text-secondary, #B8B0D8)" }}
        >
          Already have an account?{" "}
          <Link
            href="/user"
            className="font-medium"
            style={{ color: "var(--brand-primary, #8B5CF6)" }}
          >
            Sign in
          </Link>
        </p>
      </div>
    </main>
  )
}

"use client"

import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
} from '@/components/ui/dialog'

interface AuthGateDialogProps {
  open: boolean
  description: string
  onClose: () => void
  onOAuthClick: (provider: 'google' | 'discord' | 'microsoft') => void
}

const OAUTH_PROVIDERS = [
  { key: 'google', label: 'Continue with Google' },
  { key: 'discord', label: 'Continue with Discord' },
  { key: 'microsoft', label: 'Continue with Microsoft' },
] as const

export function AuthGateDialog({ open, description, onClose, onOAuthClick }: AuthGateDialogProps) {
  return (
    <Dialog open={open} onOpenChange={(isOpen) => { if (!isOpen) onClose() }}>
      <DialogContent className="max-w-sm">
        <DialogHeader>
          <DialogTitle>Sign in to continue</DialogTitle>
          <DialogDescription>{description}</DialogDescription>
        </DialogHeader>
        <div className="flex flex-col gap-3 pt-2">
          {OAUTH_PROVIDERS.map((provider, index) => (
            <button
              key={provider.key}
              type="button"
              autoFocus={index === 0}
              onClick={() => onOAuthClick(provider.key)}
              className="flex w-full items-center justify-center gap-2 rounded-md border border-input bg-background px-4 py-2.5 text-sm font-medium transition-colors hover:bg-accent hover:text-accent-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring"
            >
              {provider.label}
            </button>
          ))}
        </div>
      </DialogContent>
    </Dialog>
  )
}

"use client"

import { useState } from "react"
import { cn } from "@/lib/utils"
import { OAUTH_PROVIDERS, initiateOAuthLogin, type OAuthProvider } from "@/lib/oauth"

interface SocialLoginButtonsProps {
  returnUrl?: string
  className?: string
  disabled?: boolean
  variant?: "login" | "register" | "link"
  onError?: (error: string) => void
}

// Social provider icons as SVG components
const SocialIcons = {
